selector_to_html = {"a[href=\"#lbmpiezoarray\"]": "<h4 class=\"tippy-header\" style=\"margin-top: 0;\">LBMPiezoArray<a class=\"headerlink\" href=\"#lbmpiezoarray\" title=\"Link to this heading\">#</a></h4><p>Combined LBM + piezo, typically for pollen calibration. Each piezo step\nends up as a z-plane in the canonical layout, and the LBM beamlets land on\nthe channel axis.</p>", "a[href=\"#common-properties\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Common Properties<a class=\"headerlink\" href=\"#common-properties\" title=\"Link to this heading\">#</a></h2><p>All array types provide:</p>", "a[href=\"#writing-data\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Writing Data<a class=\"headerlink\" href=\"#writing-data\" title=\"Link to this heading\">#</a></h2><p>All array types support <code class=\"docutils literal notranslate\"><span class=\"pre\">imwrite()</span></code>:</p>", "a[href=\"#api-reference\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">API Reference<a class=\"headerlink\" href=\"#api-reference\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#piezoarray\"]": "<h4 class=\"tippy-header\" style=\"margin-top: 0;\">PiezoArray<a class=\"headerlink\" href=\"#piezoarray\" title=\"Link to this heading\">#</a></h4><p>Aquisitions using the ScanImage Piezo <code class=\"docutils literal notranslate\"><span class=\"pre\">hStackManager</span></code> produce z-stacks with optional frame averaging.</p>", "a[href=\"#scanimage-arrays\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">ScanImage Arrays<a class=\"headerlink\" href=\"#scanimage-arrays\" title=\"Link to this heading\">#</a></h3><p>Returned when reading raw ScanImage TIFF files. <code class=\"docutils literal notranslate\"><span class=\"pre\">imread()</span></code> auto-detects the stack type:</p><p>This folder containing all <code class=\"docutils literal notranslate\"><span class=\"pre\">tiffs</span></code> for a single session can be passed to <code class=\"docutils literal notranslate\"><span class=\"pre\">imread</span></code>, as well as a single files or a list of files.</p>", "a[href=\"#binarray\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">BinArray<a class=\"headerlink\" href=\"#binarray\" title=\"Link to this heading\">#</a></h3><p>Direct binary file access when no ops.npy context is available. The user\nsupplies the shape explicitly; the array adopts that as <code class=\"docutils literal notranslate\"><span class=\"pre\">.shape</span></code> and pads\nout to 5D for <code class=\"docutils literal notranslate\"><span class=\"pre\">.shape5d</span></code>.</p>", "a[href=\"#h5array\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">H5Array<a class=\"headerlink\" href=\"#h5array\" title=\"Link to this heading\">#</a></h3><p>HDF5 datasets with auto-detection of common dataset names. Reads from\n<code class=\"docutils literal notranslate\"><span class=\"pre\">/mov</span></code> by default \u2014 same name <code class=\"docutils literal notranslate\"><span class=\"pre\">mbo.imwrite(...,</span> <span class=\"pre\">ext=\".h5\")</span></code> writes to \u2014\nfalling back to <code class=\"docutils literal notranslate\"><span class=\"pre\">/data</span></code> or the first available dataset.</p>", "a[href=\"#detection-logic\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Detection Logic<a class=\"headerlink\" href=\"#detection-logic\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#suite2parray\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Suite2pArray<a class=\"headerlink\" href=\"#suite2parray\" title=\"Link to this heading\">#</a></h3><p>Suite2p binary files with full ops.npy context.</p>", "a[href=\"#lbmarray\"]": "<h4 class=\"tippy-header\" style=\"margin-top: 0;\">LBMArray<a class=\"headerlink\" href=\"#lbmarray\" title=\"Link to this heading\">#</a></h4><p>Light Beads Microscopy with z-planes interleaved as ScanImage channels.</p>", "a[href=\"#tiffarray\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">TiffArray<a class=\"headerlink\" href=\"#tiffarray\" title=\"Link to this heading\">#</a></h3><p>Universal TIFF reader for non-ScanImage files. Automatically handles standard TIFF stacks,\nImageJ hyperstacks (interleaved TZYX), and multi-plane volumes (planeXX.tiff directories).</p><p><code class=\"docutils literal notranslate\"><span class=\"pre\">TiffArray</span></code> is the only array class that reports a <em>natural rank</em> <code class=\"docutils literal notranslate\"><span class=\"pre\">.shape</span></code> \u2014\nit returns whatever the file actually has on disk (2D, 3D, 4D, or 5D). Use\n<code class=\"docutils literal notranslate\"><span class=\"pre\">.shape5d</span></code> to always get the canonical TCZYX layout.</p>", "a[href=\"#numpyarray\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">NumpyArray<a class=\"headerlink\" href=\"#numpyarray\" title=\"Link to this heading\">#</a></h3><p>Wraps <code class=\"docutils literal notranslate\"><span class=\"pre\">.npy</span></code> files (memory-mapped) or in-memory numpy arrays. Numpy input\nof any rank up to 5D is accepted; the missing dims are inferred from shape\nheuristics and recorded on <code class=\"docutils literal notranslate\"><span class=\"pre\">.shape5d</span></code>.</p>", "a[href=\"#the-5d-contract\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">The 5D contract<a class=\"headerlink\" href=\"#the-5d-contract\" title=\"Link to this heading\">#</a></h2><p>Every array returned by <code class=\"docutils literal notranslate\"><span class=\"pre\">imread()</span></code> reports a canonical 5D <strong>TCZYX</strong> layout via <code class=\"docutils literal notranslate\"><span class=\"pre\">.shape5d</span></code>,\nregardless of how many dimensions the underlying file actually has on disk.\nThe dimension order is fixed:</p>", "a[href=\"#file-formats\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">File Formats<a class=\"headerlink\" href=\"#file-formats\" title=\"Link to this heading\">#</a></h1><p><code class=\"docutils literal notranslate\"><span class=\"pre\">imread()</span></code> and the GUI file dialogs are primarily designed to read <a class=\"reference external\" href=\"https://docs.scanimage.org/\">ScanImage</a> TIFFs\nand future raw filetypes supported at the <a class=\"reference external\" href=\"https://millerbrainobservatory.github.io/\">Miller Brain Observatory</a>.</p><p>The raw metadata is made <a class=\"reference external\" href=\"https://www.openmicroscopy.org/ome-xml/\">OME</a> and ImageJ/Fiji compatible when writing to disk, ensuring downstream tools can interpret volumetric and multi-channel data correctly.</p>", "a[href=\"#quick-reference\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Quick Reference<a class=\"headerlink\" href=\"#quick-reference\" title=\"Link to this heading\">#</a></h2><p>The <code class=\"docutils literal notranslate\"><span class=\"pre\">shape5d</span></code> column shows what <code class=\"docutils literal notranslate\"><span class=\"pre\">.shape5d</span></code> reports for a typical file. The\n<code class=\"docutils literal notranslate\"><span class=\"pre\">.shape</span></code> column shows what plain <code class=\"docutils literal notranslate\"><span class=\"pre\">.shape</span></code> returns (only differs from <code class=\"docutils literal notranslate\"><span class=\"pre\">.shape5d</span></code>\nfor the natural-rank <code class=\"docutils literal notranslate\"><span class=\"pre\">TiffArray</span></code>).</p>", "a[href=\"#array-types\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Array Types<a class=\"headerlink\" href=\"#array-types\" title=\"Link to this heading\">#</a></h2><h3>ScanImage Arrays<a class=\"headerlink\" href=\"#scanimage-arrays\" title=\"Link to this heading\">#</a></h3><p>Returned when reading raw ScanImage TIFF files. <code class=\"docutils literal notranslate\"><span class=\"pre\">imread()</span></code> auto-detects the stack type:</p><p>This folder containing all <code class=\"docutils literal notranslate\"><span class=\"pre\">tiffs</span></code> for a single session can be passed to <code class=\"docutils literal notranslate\"><span class=\"pre\">imread</span></code>, as well as a single files or a list of files.</p>", "a[href=\"#singleplanearray\"]": "<h4 class=\"tippy-header\" style=\"margin-top: 0;\">SinglePlaneArray<a class=\"headerlink\" href=\"#singleplanearray\" title=\"Link to this heading\">#</a></h4><p>Single-plane time series (no z-stack).</p>", "a[href=\"#zarrarray\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">ZarrArray<a class=\"headerlink\" href=\"#zarrarray\" title=\"Link to this heading\">#</a></h3><p>Zarr v3 stores including OME-Zarr.</p>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false,

            });
        };
    };
    console.log("tippy tips loaded!");
};
